-- ----------------------------------------------------------------------------
-- Axioms: Non-negotiable invariants the platform must obey. Load-bearing constraints, not per-loop work. Captured from the gauntlet conversation.
-- ----------------------------------------------------------------------------
INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-llm-no-vote', 'The LLM never gets a vote on the conclusion.', 'Demotes the model to intake-clerk + lab; the verdict is the deterministic DAG''s, never the model''s.', 'trust-boundary') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-keystone-computed', 'IsClinicallyActionable is computed, never entered.', 'No field a curator (human or LLM) can set to make the diagnosis come out right.', 'solve-by-inference') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-line-in-dag', 'The trust boundary is a line in the DAG: fields with a formula are the model''s; raw-input leaf fields are the LLM''s (or a human''s).', 'Makes the boundary mechanically checkable rather than a vibe.', 'trust-boundary') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-llm-leaves-only', 'The LLM does exactly two things, both at the leaf layer: interpret intake facts, and produce synthetic-but-transparent test results.', 'Intake clerk + lab — the un-alarming medical roles. It computes no higher-order inference.', 'trust-boundary') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-every-choice-knob', 'Every choice the LLM makes is a literal, editable knob in the admin UI.', 'The model''s judgment is fully externalized; a wrong input is nudged, not re-prompted.', 'knob') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-formula-local-edit', 'Every DAG formula is inspectable and correctable in place, like a spreadsheet cell.', 'Editing a value or formula body is local to its dependency subtree; only retyping/regraphing ripples.', 'knob') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-independent-witness', 'Extraction and derivation are verifiable independently (three-panel witness).', 'Input case text -> extracted facts w/ provenance -> deterministic diagnosis. Defeats the laundering objection.', 'witness') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-both-verdicts', 'The same deterministic machine must land on either side and name the single deciding gate.', 'An engine that only ever says "actionable" proves nothing.', 'solve-by-inference') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-report-derived-not-prose', 'The diagnosis report is derived, never authored as prose; it is structured natural language assembled from the DAG.', 'A prose writeup would be a second, unwitnessed surface where a hallucination could hide. The report must be a deterministic projection of facts already in the graph, the same way Postgres views are.', 'report-derivation') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-report-total-coverage', 'Every word the patient gave us, and every node linked to that patient in the DAG down to ground truth, is represented somewhere in that patient''s report.', 'Completeness is the whole point: nothing the patient said and no derived fact may silently vanish from the writeup. If a value mattered enough to enter the DAG, it earns a sentence (or a deliberate, predicate-suppressed absence).', 'report-derivation') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-report-cell-simple', 'No single piece of report language is more complex than one spreadsheet cell: it references sibling values directly and does no joins or group-bys.', 'CMCC/SDLAF discipline. A narrative fragment is a calculated field on a row; it reads other fields of that same row (and global phrases from __meta), never traverses or aggregates. Complex sentences are decomposed into constituent fragment fields, each one cell-simple.', 'report-derivation') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-report-predicate-gated', 'A fragment''s language only appears when its predicates hold for that row; irrelevant language is suppressed per case.', 'Case-by-case, not a globally imposed template. The same field yields "normal temperature", "light fever", or "severe fever" depending on the row''s own value; a fragment whose predicate is false renders empty and contributes nothing to that patient''s report.', 'report-derivation') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-report-intermediate-translations', 'Complex language is built from intermediate translation fields: calculated text fragments composed from other predicates on the same row, then composed upward.', 'The way to keep every piece cell-simple is to pull a complex sentence apart into its constituent fragments, each its own field, and let higher fragments reference lower ones. The report is the top of that composition, not a monolith.', 'report-derivation') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-report-reuse-global-phrases', 'Common, reusable language lives once in the __meta settings table and is referenced by fragments; it is not re-implemented per case.', 'Literal global phrases ("The patient presented with…") and shared banding vocabulary belong in __meta so they are authored and corrected in one place. Fragments reference them; the per-row logic stays contextual while the wording stays DRY.', 'report-derivation') ON CONFLICT (axiom_id) DO NOTHING;

INSERT INTO axioms (axiom_id, statement, rationale, category)
VALUES ('ax-schema-rulespeak-report-derived', 'The schema may be expressed in RuleSpeak-style language, but the diagnosis report itself is derived (rendered), not declared.', 'RuleSpeak documents the rules; it is not the patient-facing artifact. The report is a rendered projection of each patient''s row values through the fragment fields — generated by a thin renderer that only concatenates already-derived, predicate-gated fragments in order.', 'report-derivation') ON CONFLICT (axiom_id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- TestsForSuccess: Falsifiable conditions that prove the axioms hold. The human-readable index of what each demonstration shows; many are realized in the witnessed harness.
-- ----------------------------------------------------------------------------
INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-one-gate-each', 'Five of seven patients fail, each on exactly one gate.', 'Coverage matrix in scenarios.md; L6/L7 harness assert the deciding gate per patient.', 'admin-app/tests/L6-gates.test.js', 'red') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-both-sides', 'The same machine produces TRUE for {A,G} and FALSE for {B,C,D,E,F}.', 'L7-cohort.test.js asserts exactly {A,G} actionable as a set.', 'admin-app/tests/L7-cohort.test.js', 'red') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-no-hand-entry', 'Raw facts alone derive the keystone with no hand-entered answer anywhere.', 'Every leaf in the harness is a raw observation; keystone == AND(gates) cross-check.', 'admin-app/tests/L7-keystone.test.js', 'red') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-extraction-faithful', 'Extracted leaf facts are checkable against the source case text, independently of the verdict.', 'Three-panel witness view: per-fact provenance pointer back into the case text.', '', 'planned') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-all-seven', 'All seven oracle patients resolve to their expected keystone value.', 'Build verification asserts the scenarios.md oracle against vw_individualpredictions.', 'admin-app/tests/L7-keystone.test.js', 'red') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-witnessed-reasoning', 'Each derived node carries an expert-verifiable line of reasoning.', 'Derivation trace from derivation-spec.md printed in every test name/failure.', 'admin-app/tests/README.md', 'red') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-report-covers-every-word', 'Every word the patient gave us appears somewhere in that patient''s derived report (no patient input is dropped).', 'Coverage check: tokenize each patient''s source intake text; assert each meaningful token is traceable into at least one rendered report fragment (directly quoted or its derived translation).', 'admin-app/tests/report-coverage.test.js', 'planned') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-report-covers-every-dag-node', 'Every DAG node linked to a patient, down to ground truth, is represented somewhere in that patient''s report.', 'Walk the patient''s subgraph (keystone -> gates -> evidence -> raw leaves); assert each visited node contributes at least one rendered fragment, or is deliberately suppressed by a false predicate that the report names.', 'admin-app/tests/report-coverage.test.js', 'planned') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-report-cell-simple', 'No narrative fragment field traverses, joins, or aggregates; each reads only sibling fields of its own row plus __meta__ phrases.', 'Static lint over fragment formulas: reject any formula that references another table or a rollup/lookup across rows; fragments may reference {{SiblingField}} and __meta__ keys only.', 'admin-app/tests/report-fragments.test.js', 'planned') ON CONFLICT (test_for_success_id) DO NOTHING;

INSERT INTO tests_for_success (test_for_success_id, claim, how_witnessed, related_harness_file, status)
VALUES ('tfs-report-deterministic', 'The same patient row always renders the byte-identical report; the report is a pure projection of the DAG with no model in the loop.', 'Render each patient twice and diff; assert zero difference and that the renderer makes no LLM/network calls.', 'admin-app/tests/report-deterministic.test.js', 'planned') ON CONFLICT (test_for_success_id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- Features: Buildable capabilities surfaced by the conversation. Coarser grain than loops; AssignedLoop links a feature to the loop that delivers it (nullable until scheduled).
-- ----------------------------------------------------------------------------
INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-llm-intake-clerk', 'LLM intake clerk', 'LLM reads a natural-language case and writes raw intake observation rows (ancestry, allele freqs, presenting facts) to base tables.', '') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-synthetic-lab', 'Synthetic-but-transparent lab generator', 'LLM emits the case''s test results (effect sizes/SEs, replication signs/p-values, permutation effect sizes, calibration coverage) as visible, sourced, editable leaf rows.', '') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-three-panel-witness', 'Three-panel witness view', 'Input case text | extracted facts with provenance | deterministic diagnosis + four-gate trace.', '') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-knob-edit-ui', 'Knob-editing admin UI', 'Every LLM-produced leaf value is an editable field; correcting it re-derives the DAG.', 'loop-2') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-gate-explainability', 'Gate explainability', 'For a patient, show why each gate passed/failed by walking one level down (coverage, cross-ancestry count, etc.).', 'loop-3') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-diagnosis-writeup', 'Per-patient diagnosis writeup', 'Doctor-style Markdown writeup (-> diagnosis.pdf once green) produced as an artifact of a passing run.', '') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-derived-report-fragments', 'Derived narrative fragment fields', 'Per-row calculated text fields that turn each fact into structured natural language, predicate-gated and case-by-case (e.g. Individual.TemperatureNarrative -> ''normal temperature'' | ''light fever'' | ''severe fever'' from the row''s own value). Each fragment is one spreadsheet-cell formula: it reads sibling fields and __meta__ phrases only, no joins or aggregations. Complex sentences are decomposed into constituent intermediate-translation fragments composed upward.', '') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-report-meta-phrasebook', 'Global phrasebook in __meta__', 'Reusable, contextual language atoms stored once in the __meta__ settings table — literal global phrases (''The patient presented with…'') and shared banding vocabulary — referenced by fragment fields so common language is authored/corrected in one place, never re-implemented per case.', '') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-report-renderer', 'Thin Python report renderer (replaces handlebars)', 'Replaces the json-hbars-transform plan step with a small Python renderer whose only job is to read each patient''s derived fragment fields from vw_* views and concatenate the non-empty, predicate-gated fragments in order into the diagnosis report (Markdown -> diagnosis.pdf). All sentence wording lives in the rulebook as calculated fields; the renderer owns no business or narrative logic.', '') ON CONFLICT (feature_id) DO NOTHING;

INSERT INTO features (feature_id, title, description, assigned_loop)
VALUES ('feat-report-total-coverage-check', 'Report total-coverage harness', 'Tests that every patient word and every linked DAG node down to ground truth is represented in that patient''s report (see tfs-report-covers-every-word, tfs-report-covers-every-dag-node).', '') ON CONFLICT (feature_id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- OpenQuestions: Decisions still pending, captured so they are not silently re-litigated in a later session.
-- ----------------------------------------------------------------------------
INSERT INTO open_questions (open_question_id, question, context, resolution, is_resolved)
VALUES ('oq-publish-now', 'Publish README now as a design/thesis doc, or hold until the harness goes green?', 'Repo is at Loop 0.5 (harness red, no LLM intake yet). Receipts land harder green.', '', FALSE) ON CONFLICT (open_question_id) DO NOTHING;

INSERT INTO open_questions (open_question_id, question, context, resolution, is_resolved)
VALUES ('oq-extract-vs-invent', 'Does the LLM extract facts present in the case, or invent plausible facts for a described case?', 'Mode #1 (extract) vs mode #2 (invent) changes how strong the claim is.', 'Mode #1 at intake (extract/interpret), and synthetic-but-transparent test results for the invented case — every number visible, sourced, editable.', TRUE) ON CONFLICT (open_question_id) DO NOTHING;

INSERT INTO open_questions (open_question_id, question, context, resolution, is_resolved)
VALUES ('oq-reworded-prompt', 'Confirm the reworded README prompt shares no distinctive phrasing with the prospect''s original.', 'Anonymity / no verbatim leakage before publishing.', '', FALSE) ON CONFLICT (open_question_id) DO NOTHING;

INSERT INTO open_questions (open_question_id, question, context, resolution, is_resolved)
VALUES ('oq-fragment-fields-where', 'On which tables do the narrative fragment fields live, and how are per-case fragments composed up into one report — section order, headers, grouping?', 'Decision is ''pure derived fields'': sentence wording is per-row calculated fields (cell-simple, predicate-gated), reusable atoms in __meta__. Still open: do fragments hang off the patient/IndividualPredictions row and reference sibling facts, or off each evidence/gate row and roll up as text? And the renderer owns only ordering/concatenation — confirm it never composes wording. This is the next loop''s design.', '', FALSE) ON CONFLICT (open_question_id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- NonGoals: Explicit out-of-scope statements — the positive twin of the anti-hallucination ledger. Stops scope creep.
-- ----------------------------------------------------------------------------
INSERT INTO non_goals (non_goal_id, statement, why_excluded)
VALUES ('ng-clinical-use', 'This is not validated clinical decision support and must never be used for clinical purposes.', 'Demonstration of inference structure only; all patients synthetic, all figures literature ranges.') ON CONFLICT (non_goal_id) DO NOTHING;

INSERT INTO non_goals (non_goal_id, statement, why_excluded)
VALUES ('ng-crud-ui', 'This is not a CRUD UI.', 'The home screen is the witnessed red/green harness; the payoff is a derived diagnosis writeup.') ON CONFLICT (non_goal_id) DO NOTHING;

INSERT INTO non_goals (non_goal_id, statement, why_excluded)
VALUES ('ng-llm-reasoning', 'The LLM does not perform higher-order reasoning or render the diagnosis.', 'All reasoning lives in the open, editable DAG; the LLM is intake clerk + lab only.') ON CONFLICT (non_goal_id) DO NOTHING;

INSERT INTO non_goals (non_goal_id, statement, why_excluded)
VALUES ('ng-full-breadth', 'The full omics breadth (counterfactual trajectories, most modalities, epistasis, exposures) is not on the keystone''s dependency path.', 'Kept as deliberate sparse context for breadth; pulled onto the path only when it earns its place (anti-hallucination rule).') ON CONFLICT (non_goal_id) DO NOTHING;

INSERT INTO non_goals (non_goal_id, statement, why_excluded)
VALUES ('ng-publish-verbatim', 'Never publish the prospect''s verbatim problem text.', 'Anonymity / good manners; the public artifact uses a reworded generic grand-challenge prompt.') ON CONFLICT (non_goal_id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- GlossaryTerms: Vocabulary coined in the gauntlet conversation, so the framing is shared and stable across sessions.
-- ----------------------------------------------------------------------------
INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-knob', 'knob', 'A literal, editable leaf value in the admin UI representing one choice the LLM (or a human) made; nudged, not re-prompted, when wrong.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-intake-clerk-lab', 'intake clerk + lab', 'The only two roles the LLM plays: interpret intake facts (clerk) and produce the case''s test results (lab). Never the diagnostician.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-line-in-dag', 'line in the DAG', 'The trust boundary, stated mechanically: fields with a formula belong to the model; raw-input leaf fields are the LLM''s or a human''s.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-three-panel-witness', 'three-panel witness', 'Input case text | extracted facts with per-fact provenance | deterministic diagnosis + gate trace — the two halves checkable independently.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-fake-but-transparent', 'fake-but-transparent', 'Test results are synthetic (the case is invented) but every number is visible, sourced to the case, and editable; nothing is hidden.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-laundering-objection', 'laundering objection', 'The skeptic''s claim that a deterministic function over LLM-chosen inputs just launders a hallucination; defeated by externalized knobs + independent witness.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-disease-state-simulator', 'disease state simulator', 'The v2 layer the audit asked for: disease modeled as a WITNESSED state machine whose transitions fire only on raw longitudinal observations (rising anti-dsDNA, falling C3/C4, proteinuria). Current state and dwell-time are derived & bitemporal — the contrast the audit drew with an ''evidence gate''.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-evidence-gate', 'evidence gate', 'The v1 layer: per-patient adjudication of whether a prediction is trustworthy enough to act on (the four gates + IsClinicallyActionable). v2 keeps this and adds the disease-state simulator above it on the same hub.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-disease-progression-machine', 'disease progression machine', 'A state machine on the polymorphic StateMachines substrate whose subject is a patient''s disease course (presymptomatic -> serologic-active -> early-nephritis -> renal-flare-risk -> biopsy-indicated). Transitions are raw-leaf-triggered; current state is the derived IsCurrent occupancy.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-dwell-time', 'dwell time', 'Bitemporal derivation: how long a subject has been in a disease state (now - EnteredAt while current; ExitedAt - EnteredAt once left). The audit asked for ''how long has the patient/disease been in a state'' — this is that, as a formula.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-serology-trajectory', 'serology trajectory', 'The raw longitudinal leaves driving progression: anti-dsDNA titre trend (rising/stable/falling), complement C3/C4 trend, proteinuria. The LLM/lab may emit these; everything above them is derived.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-treatment-line-recommendation', 'treatment line recommendation', 'Derived field: given the patient''s confirmed causal mechanism + current disease state, the recommended therapy (MMF vs belimumab vs anifrolumab) and the single deciding reason. The audit''s second worked example.') ON CONFLICT (glossary_term_id) DO NOTHING;

INSERT INTO glossary_terms (glossary_term_id, term, definition)
VALUES ('gt-corpus-discovery', 'corpus discovery', 'The cohort-level surface where causal-hypothesis patterns EMERGE across many patients (vs v1''s per-patient verdicts). Discovery is inherently corpus-level; this is the v2 reframe of the audit''s ''you don''t do discovery'' critique.') ON CONFLICT (glossary_term_id) DO NOTHING;

-- ----------------------------------------------------------------------------
-- LeopoldLoops: The ordered Leopold loops that build this platform, as data. The derived plan (LEOPOLD_LOOPING_PLAN.md, via json-hbars-transform) is generated from these rows; Completedness decides what shows in the current PLAN.
-- ----------------------------------------------------------------------------
INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-0', '0', 'Solve-by-inference rulebook', 'Convert 7 hand-entered answers to derived; add evidence/replication/control/calibration tables; wire raw observations to keystone.', 'done', 'rule: keystone IsClinicallyActionable now derived from observations', 'state: Loop 0 - Postgres solve-by-inference verified', 0, '[DONE]', ' - rule `rule: keystone IsClinicallyActionable now derived from observations`; state `state: Loop 0 - Postgres solve-by-inference verified`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-0-5', '0.5', 'Test Harness First (the red contract)', 'Ship a witnessed inference harness asserting the entire DAG x 7 patients via the app API; red on arrival, load-bearing.', 'done', 'none - app-only loop, test-harness-first, no rule change', 'state: Loop 0.5 - red witnessed-inference harness is the app''s contract', 1, '[DONE]', ' - rule `none - app-only loop, test-harness-first, no rule change`; state `state: Loop 0.5 - red witnessed-inference harness is the app''s contract`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-1', '1', 'Intake app skeleton', 'Turn keystone-level red tests green: wire cohort + prediction-panel endpoints reading vw_*.', 'done', 'none - app-only loop, no rule change', 'state: Loop 1 - read-only intake app surfaces the keystone', 2, '[DONE]', ' - rule `none - app-only loop, no rule change`; state `state: Loop 1 - read-only intake app surfaces the keystone`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-2', '2', 'Patient intake (facts in)', 'Form writes a new Individual + child observation rows to base tables, then re-reads the derived panel. The knob-editing payoff.', 'done', 'rule (if any) for new intake field', 'state: Loop 2 - facts-in to derived diagnosis works end to end', 3, '[DONE]', ' - rule `rule (if any) for new intake field`; state `state: Loop 2 - facts-in to derived diagnosis works end to end`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-3', '3', '3-panel witness — provenance back into the case text', 'Show why each gate passed/failed one level down; consider installing the explainer-DAG transpiler.', 'done', 'rule: install explainer-dag', 'state: Loop 3 - gate explainability', 4, '[DONE]', ' - rule `rule: install explainer-dag`; state `state: Loop 3 - gate explainability`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-4', '4', 'Second prediction type (severity)', 'Add a derived severity prediction grounded in ClinicalPhenotypes.SeverityScore; pull one context table onto the load-bearing path.', 'done', 'rule: derive a severity prediction (IsSeverityActionable) chained to the onset gates', 'state: Loop 4 - severity prediction (second prediction type) green', 5, '[DONE]', ' - rule `rule: derive a severity prediction (IsSeverityActionable) chained to the onset gates`; state `state: Loop 4 - severity prediction (second prediction type) green`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-5', '5', 'Treatment-response prediction', 'Derive a treatment-response prediction from Treatments + mechanism match; surface in the panel.', 'done', 'rule: derive a treatment-response prediction (IsTreatmentResponseActionable) via mechanism match', 'state: Loop 5 - treatment-response prediction (third prediction type) green', 6, '[DONE]', ' - rule `rule: derive a treatment-response prediction (IsTreatmentResponseActionable) via mechanism match`; state `state: Loop 5 - treatment-response prediction (third prediction type) green`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-vocab-completeness', '6', 'Vocabulary completeness - every audit-named concept enters the hub', 'Answer the audit''s breadth: bring every concept the physician named (lupus nephritis, NPSLE, cutaneous lupus, sero+/-RA, erosive disease, axial PsA, enthesitis, dactylitis, uveitis, IBD overlap, organ damage, flare patterns, treatment lines, SLEDAI/DAS28) into the hub as DiseaseDomainConcepts, each with an honest ModelingStatus (deep-DAG / schema / vocabulary). Coverage becomes checkable by grep, not by trust.', 'done', 'rule: DiseaseDomainConcepts - every audit-named concept in the hub with honest ModelingStatus', 'state: v2 step1 - vocabulary completeness; coverage checkable by grep', 7, '[DONE]', ' - rule `rule: DiseaseDomainConcepts - every audit-named concept in the hub with honest ModelingStatus`; state `state: v2 step1 - vocabulary completeness; coverage checkable by grep`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-disease-state', '7', 'Disease-state simulator - the layer the audit said did not exist', 'Reframe: v1 was a per-patient evidence gate; v2 adds the disease-state layer. A disease progressing is a state machine (lupus-nephritis-progression: Presymptomatic then SerologicActive then EarlyNephritis then RenalFlareRisk then BiopsyIndicated) whose CURRENT state is DERIVED purely from raw serology leaves (rising anti-dsDNA + falling complement + proteinuria + sediment) - never hand-set. Bitemporal DwellDays answers the audit''s ''how long in this state.'' Same trust boundary: labs are the LLM''s/clinician''s, the state is the model''s. Diego Santos''s first worked example computes (derived SledaiScore 12, High/flare).', 'done', 'rule: lupus-nephritis-progression state machine - disease state DERIVED from raw serology', 'state: v2 step3 - disease-state simulator; harness green, counter-example witnessed', 8, '[DONE]', ' - rule `rule: lupus-nephritis-progression state machine - disease state DERIVED from raw serology`; state `state: v2 step3 - disease-state simulator; harness green, counter-example witnessed`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-treatment-line', '8', 'Treatment-line recommendation + the disagreement counter-example', 'The audit''s second worked example, computed: a derived RecommendedTreatmentLine + single TreatmentLineDecidingFactor (mycophenolate for active nephritis, anifrolumab for type-I-IFN, belimumab for autoantibody-driven, secukinumab for IL-17/23) - differentiated by confirmed mechanism x disease state, never by a label. The load-bearing proof: Diego is progression_vs_actionability_disagree = TRUE - the disease-state simulator says he IS progressing (BiopsyIndicated, high activity) while the actionability gate says NOT actionable (cryptic-relatedness leakage). A pure evidence gate could never produce that sentence; that it can is the proof v2 != v1 relabeled.', 'done', 'rule: RecommendedTreatmentLine + progression_vs_actionability_disagree counter-example', 'state: v2 - treatment-line + disagreement; the two layers proven independent', 9, '[DONE]', ' - rule `rule: RecommendedTreatmentLine + progression_vs_actionability_disagree counter-example`; state `state: v2 - treatment-line + disagreement; the two layers proven independent`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-cohort-discovery', '9', 'Cohort discovery board - the corpus-level surface', 'The doctor''s deepest point: discovery is corpus-level - a single chart never discovers a mechanism, a pattern across many patients does. Build the top-level, all-roles Cohort discovery board over a 12-member claim-bearing cohort: the disease-state map, the emergent serology-signature scatter, the disease-vs-evidence disagreement board, and the treatment-line distribution - all reading derived fields. Per-patient progression + treatment-line tabs hang off the same model. The punchline, sorted to the top of the nav.', 'done', 'rule: 12-member cohort expansion; corpus-level derived fields for the discovery board', 'state: v2 steps9-10 - Cohort discovery is the top-level all-roles nav item', 10, '[DONE]', ' - rule `rule: 12-member cohort expansion; corpus-level derived fields for the discovery board`; state `state: v2 steps9-10 - Cohort discovery is the top-level all-roles nav item`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-progression-admin', '10', 'Progression machine in the state-machine admin', 'The one concrete unbuilt admin-witness item. StateMachineView is hardcoded to diagnosis-lifecycle; lupus-nephritis-progression already lives in vw_state_machines and is served by the same router. Make StateMachineView select the machine (a binding change, not a model change): render its states, the 5 raw-leaf-triggered transition rules, and a per-state cohort-occupancy strip. Closes the loop between the disease-state simulator and its admin witness.', 'next', '', 'state: Loop 10 - progression machine bound into the state-machine admin', 11, '[NEXT]', ' - state `state: Loop 10 - progression machine bound into the state-machine admin`') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-serology-discovery', '11', 'Serology-signature discovery - emergent cluster, not a label', 'Make the discovery claim falsifiable at corpus scale. The serology signature that PRECEDES nephritis (the rising-anti-dsDNA / falling-complement trajectory) should surface as a DERIVED corpus-level cluster on the cohort scatter - emergent from the population''s raw serology series, not a label anyone assigned. Derive the cluster membership / signature-strength field in the hub so the discovery is reproducible and witnessed, then surface it on the cohort board. This is the literal answer to ''discovery is corpus-level.''', 'planned', '', '', 12, '[PLANNED]', '') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-prune-nonloadbearing', '12', 'Prune excess engineering - keep only what is load-bearing for the v1 audit response', 'A deliberate trimming pass (NOT a delete spree). Walk the model, the app, and the docs and find anything that was UPGRADED or SUPERSEDED and now lingers as a duplicate, plus any engineering that is not actually load-bearing toward the clearest pedagogical answer to the v1 audit. Candidates to scrutinise: superseded prediction types that don''t earn their keep (e.g. a 4th parallel adverse-effect prediction once severity + treatment-response + treatment-line exist), redundant ontology slots that no longer carry a claim, and any view/endpoint with no consumer. Promotion rule inverted: if a thing is neither traceable to problem-to-solve.md nor load-bearing toward the keystone or the audit response, retire it. Goal: the clearest, most complete, DUPLICATE-FREE representation of the problem - so the audit response is concise as well as complete.', 'planned', '', '', 13, '[PLANNED]', '') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-llm-intake', '13', 'LLM intake clerk + synthetic lab', 'FUTURE ROADMAP (not part of the v1-audit response - this is the framework-thesis deliverable, the next conversation). The trust-boundary payoff: wire the LLM to read a natural-language case and write ONLY leaf observations - intake facts + synthetic-but-transparent test results - with the three-panel witness (case text / extracted facts with per-fact provenance / derived diagnosis + gate trace). The LLM never computes a higher-order inference; every value it emits is an editable knob. Demotes the model to a replaceable, fully-overridable transcriber - the structural defeat of ''a hallucination laundered through a deterministic function.''', 'roadmap', 'rule (if any) for provenance fields', 'state: LLM intake clerk, everything-is-a-knob', 14, '[ROADMAP]', '') ON CONFLICT (leopold_loop_id) DO NOTHING;

INSERT INTO leopold_loops (leopold_loop_id, loop_number, title, goal, status, rule_commit_msg, state_commit_msg, sort_order, status_badge, status_line)
VALUES ('loop-equity', '14', 'Cohort-level equity report', 'FUTURE ROADMAP (traceable to the original challenge''s equity requirement, but not part of the v1-audit response). Ancestry-equity made structural and corpus-level: calibration and actionability rates by ancestry (gates 2 and 4 of the keystone) as a derived dashboard, complementing the cohort discovery board. Equity is a checkable rate, not a promise.', 'roadmap', '', '', 15, '[ROADMAP]', '') ON CONFLICT (leopold_loop_id) DO NOTHING;

